//F. Eating Candies #include<bits/stdc++.h>using namespace std;#define int long long intsigned main(){    int t;    cin>>t;    while(t--){        int n;        cin>>n;        vector<int>arr(n);        for(int i=0;i<n;i++){            cin>>arr[i];        }            int l=0,r=0;        int i=0,j=n-1;        int count=0;        while(i<=j){            if(l<=r){                l=l+arr[i];                i++;            }            else{                r=r+arr[j];                j--;            }            if(l==r){                count=i+(n-1-j);            }        }        cout<<count<<endl;    }}